/**
 * Self-contained formalization reducer test.
 *
 * Run:
 *   pnpm run gnode -- run open-source/gnosis/src/__tests__/reduction-projection-formalization.test.ts
 */

import assert from 'node:assert';
import { deriveReductionProjectionFormalization } from '../reduction-projection-formalization';

const bundle = deriveReductionProjectionFormalization({
  generatedAt: '2026-04-08T00:00:00.000Z',
  source: 'test-suite',
  request: {
    voidSignals: [
      {
        dimension: 'temporal',
        visibleCrossings: 1,
        queueDepth: 3,
        exactWitness: false,
      },
    ],
    untanglingSignals: [
      {
        crossingNumber: 9,
        beta1: 2,
        violationPaths: 2,
        defectFamily: 'composite',
      },
    ],
    triangulationSignals: [
      {
        idPrefix: 'tri-coerce',
        mesh: {
          vertices: 6,
          edges: 12,
          faces: 8,
        },
        dimensions: [2, 3, 6, 54],
      },
    ],
  },
});

assert.strictEqual(bundle.generatedAt, '2026-04-08T00:00:00.000Z');
assert.strictEqual(bundle.source, 'test-suite');
assert.strictEqual(bundle.entries.length, 14);
assert.strictEqual(bundle.aggregate.reductions, 14);
assert.strictEqual(bundle.aggregate.paradoxCount, 8);
assert.strictEqual(
  bundle.aggregate.sandwichSatisfiedCount,
  bundle.entries.length
);
assert.strictEqual(
  bundle.aggregate.predictiveConsistentCount,
  bundle.entries.length
);
assert.ok(
  bundle.theoremIds.includes('THM-PROJECTION-PARADOX-UNIT-SANDWICH')
);
assert.ok(
  bundle.theoremIds.includes('THM-PROJECTION-PARADOX-PREDICTIVE-EXACT')
);
assert.ok(
  bundle.theoremIds.includes('THM-CROSS-REDUCTION-PROJECTION-FOLD')
);
assert.ok(
  bundle.theoremIds.includes('THM-TRIANGULATION-COERCION-MATRIX-2-3-6-54')
);
assert.ok(
  bundle.theoremIds.includes('THM-SPHERE-TRIANGULATION-BIDIRECTIONAL-ROUNDTRIP')
);
assert.ok(
  bundle.theoremIds.includes('THM-TRIANGULATION-STRICT-UNKNOT-REDUCTION')
);

console.log('reduction-projection-formalization: all tests passed');
